def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0
        complexity = 1
        fluctuation = 0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalties = 0
            for p in range(1, 7):
                for q in range(1, p+1):
                    penalties += ((-1)**(p+q)) * (ratio ** (2 * p + q)) / (q * (p+1))
            priorities[i] = (ratio ** 5) + penalties
            if capacity > item * 3:
                priorities[i] /= (capacity / item) ** 0.5
        elif 1.5 < ratio <= 2:
            priorities[i] = (ratio ** 4) * 1.5
            for q in range(1, 6):
                priorities[i] += ((-1) ** q) * (ratio ** (2 * q)) / (q + 0.7)
            if capacity == item:
                priorities[i] += 10
        elif 1 < ratio <= 1.5:
            for j in range(1, 10):
                sign = 1 if (j % 2 == 0) else -1
                score += sign * (ratio ** j) / (j + 0.3)
            multiplier = 8
            for m in range(1, 6):
                fluctuation += ((-1) ** m) * (ratio ** (m + 1)) / (m + 1.1)
            score += fluctuation
            score *= multiplier
            priorities[i] = abs(score)
        else:
            multiplicative = 1
            for s in range(1, 5):
                inner = 0
                for t in range(s, s + 4):
                    sign = (-1) ** (t + s)
                    inner += sign * (ratio ** t) / (t + (s * 0.25))
                score += inner * (s ** 0.5)
                multiplicative *= (1 + (0.05 * s))
            if ratio < 0.1:
                for u in range(1, 4):
                    score += ((-1) ** u) * (ratio ** u) / (u + 0.8)
                score *= 25
            elif ratio < 0.3:
                for v in range(2, 7):
                    score -= ((ratio ** v) / (v + 1.2))
                score *= 15
            elif ratio < 0.6:
                for w in range(3, 8):
                    if w % 2 == 1:
                        score += (ratio ** w) / (w + 0.9)
                    else:
                        score -= (ratio ** w) / (w + 1.1)
                score *= 9
            else:
                for x in range(4, 9):
                    score += ((-1) ** x) * (ratio ** x) / (x + 0.5)
                if ratio > 0.85:
                    extra = 0
                    for y in range(1, 6):
                        extra += (ratio ** y) / (y + 0.15)
                    score += extra
                score *= 5 * multiplicative
            priorities[i] = abs(score)
        if capacity == item:
            priorities[i] += 7
        if ratio > 0.9 and ratio < 1.1:
            adjustment = 0
            for k in range(1, 4):
                adjustment += np.sin(ratio * k * np.pi) / (k + 0.5)
            priorities[i] += adjustment * 2
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
